def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq
    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    # trivial cases
    if k <= 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # hypervolume computation helper (safe fallback if pygmo not available)
    def hv_of_indices(idx_list):
        if len(idx_list) == 0:
            return 0.0
        arr = points[np.array(idx_list, dtype=int)]
        if pg is None:
            # crude fallback: approximate individual hypervolume as product of (ref - pt) and ignore overlaps
            # this is only used if pygmo is not available
            diffs = np.maximum(reference_point - arr, 0.0)
            try:
                # exact for single point; for multiple points fall back to greedy inclusion-exclusion approx (very rough)
                if arr.shape[0] == 1:
                    return float(np.prod(diffs[0]))
                # approximate union by summing singles and subtracting pairwise overlaps (cheap approx)
                single = np.prod(diffs, axis=1)
                approx = float(single.sum())
                # subtract pairwise min volumes (very cheap approx)
                if arr.shape[0] > 1:
                    for i in range(arr.shape[0]):
                        for j in range(i + 1, arr.shape[0]):
                            mins = np.minimum(diffs[i], diffs[j])
                            approx -= float(np.prod(mins)) * 0.5
                return max(0.0, approx)
            except Exception:
                return 0.0
        else:
            try:
                return float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                return 0.0

    # precompute single-point hypervolumes (used as upper bounds in lazy greedy)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Lazy greedy selection using single_hvs as initial upper bounds.
    # Use a max-heap (implemented via heapq of negatives).
    heap = [(-single_hvs[i], i) for i in range(n)]
    heapq.heapify(heap)

    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    tol = 1e-12
    # Precompute pairwise distances for tie-breaking when needed
    # Only compute if space/time allows: n x n distance could be large, but we compute a compact matrix if n not huge.
    compute_distances = (n <= 2000)  # heuristic threshold
    if compute_distances:
        # squared Euclidean distances
        diff = points[:, None, :] - points[None, :, :]
        dists = np.sqrt(np.maximum((diff ** 2).sum(axis=2), 0.0))
    else:
        dists = None

    # Helper: min distance from a candidate to currently selected set (for tie-break)
    def min_dist_to_selected(idx):
        if len(selected_indices) == 0:
            return np.inf
        if compute_distances:
            return float(np.min(dists[idx, list(selected_set)]))
        else:
            # compute on the fly
            cand = points[idx]
            sel_pts = points[list(selected_set)]
            return float(np.min(np.linalg.norm(sel_pts - cand, axis=1)))

    # Main loop
    while len(selected_indices) < k and heap:
        # Pop candidate with highest upper bound
        ub_neg, idx = heapq.heappop(heap)
        ub = -ub_neg
        if idx in selected_set:
            continue
        # Recompute exact marginal gain
        delta = hv_of_indices(selected_indices + [idx]) - current_hv
        if delta < 0:
            delta = 0.0  # numerical safety
        # Peek at next best upper bound
        if heap:
            next_ub = -heap[0][0]
        else:
            next_ub = -np.inf
        # Acceptance condition: if this candidate's true marginal is >= next's upper bound (lazy greedy)
        if delta + tol >= next_ub:
            # If marginal is essentially zero and we still need points, prefer candidates with larger single_hv or diversity
            if delta <= tol:
                # choose between this candidate and the top few remaining to pick one with better diversity/single_hv
                # gather a small pool
                pool = [idx]
                # peek up to 5 more from heap
                temp = []
                for _ in range(min(5, len(heap))):
                    item = heapq.heappop(heap)
                    temp.append(item)
                    pool.append(item[1])
                # restore heap
                for item in temp:
                    heapq.heappush(heap, item)
                # evaluate diversity score = (single_hv, min_dist_to_selected)
                best = idx
                best_score = (single_hvs[idx], min_dist_to_selected(idx))
                for pid in pool:
                    sc = (single_hvs[pid], min_dist_to_selected(pid))
                    if sc > best_score:
                        best = pid
                        best_score = sc
                # if best is not the popped idx, push the popped idx back with updated bound (its delta=0)
                if best != idx:
                    # push popped one back (with its delta as new bound)
                    heapq.heappush(heap, (-delta, idx))
                    # remove best from heap (find and remove one occurrence)
                    # simple approach: lazily mark by adding a new entry for best with its single_hv and rely on duplicates
                    # add best with its single_hv if not already selected
                    if best not in selected_set:
                        heapq.heappush(heap, (-single_hvs[best], best))
                    continue
                # else accept best which is idx
            # Accept candidate
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            # Update current_hv exactly
            current_hv = hv_of_indices(selected_indices)
        else:
            # update bound for this candidate and push back
            heapq.heappush(heap, (-delta, idx))

    # If not enough selected (e.g., heap exhausted or all remaining have zero marginal), fill with highest single_hv unselected
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_set]
        remaining_sorted = sorted(remaining, key=lambda x: single_hvs[x], reverse=True)
        for idx in remaining_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
        current_hv = hv_of_indices(selected_indices)

    subset = points[np.array(selected_indices, dtype=int), :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random
    from math import isfinite
    rng = random.Random(0)

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D).")
    n, d = points.shape
    if not (isinstance(k, int) and 0 < k <= n):
        raise ValueError("k must be an integer with 0 < k <= number of points")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Hypervolume computation helper
    def hv_of_array(arr):
        if arr is None or len(arr) == 0:
            return 0.0
        try:
            return float(pg.hypervolume(np.asarray(arr, dtype=float)).compute(reference_point))
        except Exception:
            return 0.0

    def hv_of_indices(indices):
        if len(indices) == 0:
            return 0.0
        arr = points[np.array(indices, dtype=int)]
        return hv_of_array(arr)

    # Compute individual hypervolumes (single-point contributions)
    individual_hv = np.zeros(n, dtype=float)
    for i in range(n):
        try:
            individual_hv[i] = float(pg.hypervolume(points[[i]]).compute(reference_point))
        except Exception:
            individual_hv[i] = 0.0

    # Candidate preselection: choose top by individual hv (larger pool than k)
    min_pool = max(100, 10 * k)  # heuristic pool size
    num_candidates = min(n, max(k, min_pool))
    top_indices = np.argsort(individual_hv)[-num_candidates:][::-1]
    top_list = list(map(int, top_indices))

    # Pareto filter among candidates (assume minimization: smaller is better)
    # A point a dominates b if all a <= b and at least one <.
    def pareto_filter(idx_list):
        if len(idx_list) == 0:
            return []
        pts = points[np.array(idx_list, dtype=int)]
        keep = []
        N = len(idx_list)
        dominated = np.zeros(N, dtype=bool)
        for i in range(N):
            if dominated[i]:
                continue
            pi = pts[i]
            for j in range(i + 1, N):
                if dominated[j]:
                    continue
                pj = pts[j]
                le_ij = np.all(pi <= pj)
                le_ji = np.all(pj <= pi)
                if le_ij and np.any(pi < pj):
                    dominated[j] = True
                elif le_ji and np.any(pj < pi):
                    dominated[i] = True
                    break
        for i, idx in enumerate(idx_list):
            if not dominated[i]:
                keep.append(int(idx))
        return keep

    candidate_indices = pareto_filter(top_list)
    # If Pareto filter removed too many, fall back to top_list
    if len(candidate_indices) < k:
        candidate_indices = top_list[:]

    # Greedy selection: at each step pick candidate with largest marginal HV gain
    selected = []
    selected_set = set()
    current_hv = 0.0

    remaining = [int(i) for i in candidate_indices]

    # If candidate pool still smaller than k, supplement with top by individual hv
    if len(remaining) < k:
        other = [i for i in np.argsort(individual_hv)[::-1] if int(i) not in remaining]
        for i in other:
            if len(remaining) >= k:
                break
            remaining.append(int(i))

    # Main greedy loop (recompute marginal gains each round for clarity and reliability)
    tol = 1e-12
    while len(selected) < k and len(remaining) > 0:
        best_idx = None
        best_gain = -np.inf
        # Evaluate marginal gain for each remaining candidate
        for idx in remaining:
            if idx in selected_set:
                continue
            gain = hv_of_indices(selected + [idx]) - current_hv
            # numeric protection
            if not isfinite(gain):
                gain = -np.inf
            # small negative assigned to 0
            if gain < 0 and gain > -1e-12:
                gain = 0.0
            if gain > best_gain or (abs(gain - best_gain) <= 1e-15 and (best_idx is None or idx < best_idx)):
                best_gain = gain
                best_idx = idx
        if best_idx is None:
            break
        # Accept best
        selected.append(int(best_idx))
        selected_set.add(int(best_idx))
        current_hv = hv_of_indices(selected)
        # remove from remaining
        remaining = [i for i in remaining if i != best_idx]

        # If remaining pool exhausted but not k selected, fill by global best individual hv not yet selected
        if len(remaining) == 0 and len(selected) < k:
            remaining = [int(i) for i in np.argsort(individual_hv)[::-1] if int(i) not in selected_set]

    # If still not enough, pad with best by individual hv
    if len(selected) < k:
        remaining_global = [int(i) for i in np.argsort(individual_hv)[::-1] if int(i) not in selected_set]
        for idx in remaining_global:
            if len(selected) >= k:
                break
            selected.append(int(idx))
            selected_set.add(int(idx))
        current_hv = hv_of_indices(selected)

    # Local swap refinement: try to swap selected s with unselected r to improve hv
    max_swaps = max(200, 20 * k)
    improved = True
    swaps = 0
    # Prepare remaining pool (all indices not in selected_set)
    all_remaining = [i for i in range(n) if i not in selected_set]
    while improved and swaps < max_swaps:
        improved = False
        swaps += 1
        # Randomize order to avoid deterministic local minima
        rng.shuffle(selected)
        rng.shuffle(all_remaining)
        for s_idx in list(selected):
            for r_idx in list(all_remaining):
                # try swap s_idx out and r_idx in
                new_sel = [i for i in selected if i != s_idx] + [r_idx]
                new_hv = hv_of_indices(new_sel)
                if new_hv > current_hv + 1e-12:
                    # perform swap
                    selected = new_sel
                    selected_set.remove(s_idx)
                    selected_set.add(r_idx)
                    all_remaining = [i for i in range(n) if i not in selected_set]
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    # Final safety: ensure exactly k indices
    if len(selected) > k:
        selected = selected[:k]
    if len(selected) < k:
        remaining_global = [int(i) for i in np.argsort(individual_hv)[::-1] if int(i) not in selected]
        for idx in remaining_global:
            if len(selected) >= k:
                break
            selected.append(int(idx))

    subset = points[np.array(selected, dtype=int)]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = points.shape

    if k <= 0:
        return np.zeros((0, D), dtype=float)

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # Helper: compute union volume of boxes anchored at ref with upper corners given by boxes (m, D)
    def union_boxes_volume(boxes, ref):
        boxes = np.asarray(boxes, dtype=float)
        if boxes.size == 0:
            return 0.0
        # Keep only boxes with positive volume: all coordinates > ref
        mask_pos = np.all(boxes > ref, axis=1)
        boxes = boxes[mask_pos]
        if boxes.shape[0] == 0:
            return 0.0

        def _union_recursive(bxs, r):
            if bxs.shape[0] == 0:
                return 0.0
            d = r.size
            if d == 1:
                max_end = np.max(bxs[:, 0])
                return max(0.0, max_end - r[0])
            coords = np.unique(np.concatenate(([r[0]], bxs[:, 0])))
            coords.sort()
            total = 0.0
            for i in range(len(coords) - 1):
                x_left = coords[i]
                x_right = coords[i + 1]
                if x_right <= x_left:
                    continue
                mask = bxs[:, 0] >= x_right
                if not np.any(mask):
                    continue
                sub_boxes = bxs[mask][:, 1:]
                sub_ref = r[1:]
                sub_vol = _union_recursive(sub_boxes, sub_ref)
                if sub_vol > 0.0:
                    total += (x_right - x_left) * sub_vol
            return total

        return float(_union_recursive(boxes, ref))

    # If k >= N, simply return all points
    if k >= N:
        return points.copy()

    # Precompute singleton volumes as upper bounds
    single_volumes = np.zeros(N, dtype=float)
    for i in range(N):
        single_volumes[i] = union_boxes_volume(points[i:i+1, :], reference_point)

    # Build max-heap of (bound, idx) using negative values because heapq is min-heap
    heap = []
    for i in range(N):
        # Use single-point volume as initial upper bound; can be zero
        heap.append((-single_volumes[i], i))
    heapq.heapify(heap)

    selected_indices = []
    selected_mask = np.zeros(N, dtype=bool)
    selected_boxes = np.zeros((0, D), dtype=float)
    current_volume = 0.0
    tol = 1e-12

    # Lazy greedy: pop top bound, compute true marginal; if still maximal, accept; else push updated bound
    while len(selected_indices) < k and heap:
        neg_bound, idx = heapq.heappop(heap)
        if selected_mask[idx]:
            continue  # already selected via some path
        # If the stored bound is essentially zero and current_volume > 0, quick-skip to avoid heavy computation
        bound = -neg_bound
        if bound <= 0.0 and current_volume > 0.0:
            true_gain = 0.0
        else:
            # compute union with candidate
            if selected_boxes.shape[0] == 0:
                vol_with = single_volumes[idx]
            else:
                combined = np.vstack((selected_boxes, points[idx:idx+1, :]))
                vol_with = union_boxes_volume(combined, reference_point)
            true_gain = vol_with - current_volume
            # numerical negative to zero
            if true_gain < 0 and true_gain > -1e-14:
                true_gain = 0.0

        # If heap is empty, accept if gain is non-negative (or if we still need points)
        if not heap:
            accept = True
        else:
            # Compare true_gain with next highest bound in heap (which is an upper bound for others)
            next_neg_bound = heap[0][0]
            next_best_bound = -next_neg_bound
            # If true_gain >= next_best_bound - tol, then this candidate is still the best
            accept = (true_gain >= next_best_bound - tol)

        if accept:
            # select this point (even if true_gain == 0, to fill up to k)
            selected_indices.append(idx)
            selected_mask[idx] = True
            if selected_boxes.shape[0] == 0:
                selected_boxes = points[idx:idx+1, :].copy()
            else:
                selected_boxes = np.vstack((selected_boxes, points[idx:idx+1, :]))
            # update current volume fully
            current_volume = union_boxes_volume(selected_boxes, reference_point)
        else:
            # update its bound to the true_gain and push back; it might still be chosen later
            # but if true_gain is negative due to numerical issues, clip to zero
            new_bound = max(0.0, true_gain)
            heapq.heappush(heap, (-new_bound, idx))

    # If we didn't select enough (e.g., all remaining gains are zero), fill arbitrarily with remaining unselected points
    if len(selected_indices) < k:
        for i in range(N):
            if not selected_mask[i]:
                selected_indices.append(i)
                selected_mask[i] = True
                if len(selected_indices) >= k:
                    break

    selected = points[np.array(selected_indices[:k], dtype=int), :]
    # Ensure shape exactly (k, D)
    if selected.shape[0] > k:
        selected = selected[:k, :]
    elif selected.shape[0] < k:
        if selected.shape[0] == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        extra = k - selected.shape[0]
        pad = np.repeat(selected[-1:, :], extra, axis=0)
        selected = np.vstack((selected, pad))
    return selected
